--
-- Table structure for table `arbitrage_opportunities`
--

DROP TABLE IF EXISTS `arbitrage_opportunities`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `arbitrage_opportunities` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `strategy_type` enum('CROSS_EXCHANGE','TRIANGULAR','FUTURES_SPOT') COLLATE utf8mb4_unicode_ci NOT NULL,
  `symbols` json DEFAULT NULL COMMENT 'JSON array of symbols involved',
  `exchanges` json DEFAULT NULL COMMENT 'JSON array of exchange names involved',
  `buy_exchange` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Exchange to buy from',
  `sell_exchange` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Exchange to sell on',
  `buy_price` decimal(28,12) DEFAULT NULL COMMENT 'Best ask on buy exchange',
  `sell_price` decimal(28,12) DEFAULT NULL COMMENT 'Best bid on sell exchange',
  `spread_pct` decimal(12,6) DEFAULT NULL COMMENT 'Raw spread percentage',
  `theoretical_profit_pct` decimal(12,6) DEFAULT NULL COMMENT 'Profit % before fees and slippage',
  `estimated_net_profit_pct` decimal(12,6) DEFAULT NULL COMMENT 'Estimated profit % after fees and slippage',
  `estimated_slippage_pct` decimal(12,6) DEFAULT NULL COMMENT 'Estimated slippage based on orderbook depth',
  `executable_quantity` decimal(28,12) DEFAULT NULL COMMENT 'Max executable quantity in base asset',
  `executable_value_usdt` decimal(28,8) DEFAULT NULL COMMENT 'Executable notional value in USDT',
  `buy_fee_pct` decimal(10,6) DEFAULT NULL COMMENT 'Taker fee on buy side',
  `sell_fee_pct` decimal(10,6) DEFAULT NULL COMMENT 'Taker fee on sell side',
  `confidence_score` decimal(5,4) DEFAULT NULL COMMENT '0-1 confidence score',
  `risk_flags` json DEFAULT NULL COMMENT 'JSON map of risk flag names to details',
  `orderbook_depth_buy` decimal(28,8) DEFAULT NULL COMMENT 'Orderbook depth on buy side (USDT)',
  `orderbook_depth_sell` decimal(28,8) DEFAULT NULL COMMENT 'Orderbook depth on sell side (USDT)',
  `is_executable` tinyint(1) NOT NULL COMMENT 'Whether opportunity passes all pre-trade checks',
  `rejection_reason` text COLLATE utf8mb4_unicode_ci COMMENT 'Reason the opportunity was rejected',
  `detected_at` datetime NOT NULL DEFAULT (now()) COMMENT 'Timestamp when opportunity was first detected',
  `expired_at` datetime DEFAULT NULL COMMENT 'Timestamp when opportunity expired',
  `status` enum('DETECTED','EXECUTING','EXECUTED','EXPIRED','REJECTED') COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime NOT NULL DEFAULT (now()),
  `updated_at` datetime NOT NULL DEFAULT (now()),
  PRIMARY KEY (`id`),
  KEY `ix_opportunities_status` (`status`),
  KEY `ix_opportunities_strategy` (`strategy_type`),
  KEY `ix_opportunities_detected_at` (`detected_at`),
  KEY `ix_opportunities_is_executable` (`is_executable`),
  KEY `ix_opportunities_buy_sell_exchange` (`buy_exchange`,`sell_exchange`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
