--
-- Table structure for table `execution_plans`
--

DROP TABLE IF EXISTS `execution_plans`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `execution_plans` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `opportunity_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `strategy_type` enum('CROSS_EXCHANGE','TRIANGULAR','FUTURES_SPOT') COLLATE utf8mb4_unicode_ci NOT NULL,
  `mode` enum('PAPER','LIVE') COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'PAPER or LIVE trading mode',
  `target_quantity` decimal(28,12) DEFAULT NULL COMMENT 'Planned quantity in base asset',
  `target_value_usdt` decimal(28,8) DEFAULT NULL COMMENT 'Planned notional in USDT',
  `planned_profit_pct` decimal(12,6) DEFAULT NULL COMMENT 'Expected profit %',
  `status` enum('PENDING','SUBMITTING','PARTIAL_FILLED','FILLED','HEDGING','COMPLETED','FAILED','ABORTED') COLLATE utf8mb4_unicode_ci NOT NULL,
  `started_at` datetime DEFAULT NULL,
  `completed_at` datetime DEFAULT NULL,
  `actual_profit_pct` decimal(12,6) DEFAULT NULL COMMENT 'Realized profit %',
  `actual_profit_usdt` decimal(28,8) DEFAULT NULL COMMENT 'Realized profit in USDT',
  `execution_time_ms` int DEFAULT NULL COMMENT 'Total execution wall-clock time in ms',
  `error_message` text COLLATE utf8mb4_unicode_ci,
  `metadata_json` json DEFAULT NULL COMMENT 'Arbitrary execution metadata',
  `created_at` datetime NOT NULL DEFAULT (now()),
  `updated_at` datetime NOT NULL DEFAULT (now()),
  PRIMARY KEY (`id`),
  KEY `ix_execution_plans_status` (`status`),
  KEY `ix_execution_plans_opportunity` (`opportunity_id`),
  KEY `ix_execution_plans_mode` (`mode`),
  KEY `ix_execution_plans_started_at` (`started_at`),
  CONSTRAINT `execution_plans_ibfk_1` FOREIGN KEY (`opportunity_id`) REFERENCES `arbitrage_opportunities` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

