DROP TABLE IF EXISTS `rebalance_suggestions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `rebalance_suggestions` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `asset` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Asset to rebalance',
  `from_exchange` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Source exchange',
  `to_exchange` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Destination exchange',
  `suggested_quantity` decimal(28,12) DEFAULT NULL COMMENT 'Recommended transfer quantity',
  `reason` text COLLATE utf8mb4_unicode_ci COMMENT 'Why rebalance is suggested',
  `status` enum('PENDING','APPROVED','EXECUTED','DISMISSED') COLLATE utf8mb4_unicode_ci NOT NULL,
  `created_at` datetime NOT NULL DEFAULT (now()),
  `updated_at` datetime NOT NULL DEFAULT (now()),
  PRIMARY KEY (`id`),
  KEY `ix_rebalance_suggestions_asset` (`asset`),
  KEY `ix_rebalance_suggestions_status` (`status`),
  KEY `ix_rebalance_suggestions_created_at` (`created_at`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
