--
-- Table structure for table `risk_events`
--

DROP TABLE IF EXISTS `risk_events`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `risk_events` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `rule_name` varchar(100) COLLATE utf8mb4_unicode_ci NOT NULL COMMENT 'Name of the risk rule that triggered',
  `rule_category` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Category grouping (e.g. exposure, latency, spread)',
  `severity` enum('INFO','WARNING','CRITICAL') COLLATE utf8mb4_unicode_ci NOT NULL,
  `event_type` enum('BLOCKED','WARNING','ALERT') COLLATE utf8mb4_unicode_ci NOT NULL,
  `opportunity_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `execution_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `details_json` json DEFAULT NULL COMMENT 'Structured details of the risk event',
  `threshold_value` decimal(28,12) DEFAULT NULL COMMENT 'Configured threshold that was breached',
  `actual_value` decimal(28,12) DEFAULT NULL COMMENT 'Actual observed value',
  `message` text COLLATE utf8mb4_unicode_ci COMMENT 'Human-readable description',
  `created_at` datetime NOT NULL DEFAULT (now()),
  `updated_at` datetime NOT NULL DEFAULT (now()),
  PRIMARY KEY (`id`),
  KEY `ix_risk_events_severity` (`severity`),
  KEY `ix_risk_events_event_type` (`event_type`),
  KEY `ix_risk_events_rule_name` (`rule_name`),
  KEY `ix_risk_events_opportunity` (`opportunity_id`),
  KEY `ix_risk_events_execution` (`execution_id`),
  KEY `ix_risk_events_created_at` (`created_at`),
  CONSTRAINT `risk_events_ibfk_1` FOREIGN KEY (`opportunity_id`) REFERENCES `arbitrage_opportunities` (`id`) ON DELETE SET NULL,
  CONSTRAINT `risk_events_ibfk_2` FOREIGN KEY (`execution_id`) REFERENCES `execution_plans` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

